//! Hermes Universal — Tauri v2 entrypoint (shared by desktop dev and the mobile
//! Android/iOS targets). `run()` is the mobile entry point; the Android project
//! generated by `tauri android init` calls into it.
//!
//! All network traffic runs in Rust (`transport`), not the webview — see
//! `transport.rs`. The frontend drives it over IPC and reuses the JS
//! `JsonRpcGatewayClient` via an IPC-backed WebSocket.
//!
//! (Android note: the generated `RustWebView.getCookies` is patched null-safe by
//! `build.rs` to avoid a wry 0.55 crash on cookie polling — see that file.)

mod appearance;
mod audio;
mod cloud;
mod local_backend;
mod marketplace;
mod oauth;
mod pty;
mod transport;
mod voice;

use appearance::set_window_translucency;
use audio::{audio_cancel_recording, audio_start_recording, audio_stop_recording, AudioState};
use marketplace::{marketplace_fetch, marketplace_search};
use cloud::{
    portal_agent_sign_in, portal_discover_agents, portal_login, portal_logout, portal_status,
};
use local_backend::{local_backend_spawn, local_backend_status, local_backend_stop, LocalBackendState};
use oauth::{oauth_login, oauth_logout, oauth_status};
use pty::{pty_kill, pty_resize, pty_spawn, pty_write, PtyState};
use transport::{
    cookies_export, cookies_import, http_request, ws_close, ws_open, ws_send, TransportState,
};

/// Open a URL in the system browser. Routed through the opener plugin's Rust API
/// rather than its JS `openUrl` command: a Rust-internal call isn't gated by the
/// opener ACL/scope (which was silently blocking the JS path), so provider OAuth
/// sign-in and docs links reliably launch the OS browser.
#[tauri::command]
fn open_external(app: tauri::AppHandle, url: String) -> Result<(), String> {
    use tauri_plugin_opener::OpenerExt;
    app.opener()
        .open_url(url, None::<&str>)
        .map_err(|e| e.to_string())
}

/// Reveal a path in the OS file manager (Finder/Explorer/Files), selecting the
/// item. Routed through the opener plugin's Rust API — like `open_external`, a
/// Rust-internal call isn't gated by the opener ACL/scope. Desktop-local only:
/// the caller must ensure the path exists on this machine's disk.
#[tauri::command]
fn reveal_in_file_manager(app: tauri::AppHandle, path: String) -> Result<(), String> {
    use tauri_plugin_opener::OpenerExt;
    app.opener()
        .reveal_item_in_dir(path)
        .map_err(|e| e.to_string())
}

#[cfg_attr(mobile, tauri::mobile_entry_point)]
pub fn run() {
    // Route Rust `log::` output to logcat on Android (tao doesn't reliably install
    // a logger, so diagnostics were invisible). Idempotent via `init_once`.
    #[cfg(target_os = "android")]
    android_logger::init_once(
        android_logger::Config::default()
            .with_max_level(log::LevelFilter::Info)
            .with_tag("hermes"),
    );

    // Install a rustls CryptoProvider process-wide before any TLS handshake.
    // reqwest builds its own config, but tokio-tungstenite's wss:// path calls
    // ClientConfig::builder(), which resolves the process-default provider and
    // panics if the crate features ever expose more than one (or none). Pin ring
    // explicitly so public wss:// gateways (VPS/VPC with a real cert) work. This
    // is idempotent — ignore the Err when something already installed one.
    let _ = rustls::crypto::ring::default_provider().install_default();

    tauri::Builder::default()
        .plugin(tauri_plugin_os::init())
        .plugin(tauri_plugin_keyring::init())
        .plugin(tauri_plugin_mic::init())
        .plugin(tauri_plugin_opener::init())
        .plugin(tauri_plugin_haptics::init())
        .plugin(tauri_plugin_dialog::init())
        .plugin(tauri_plugin_fs::init())
        .plugin(tauri_plugin_notification::init())
        .manage(TransportState::new())
        .manage(LocalBackendState::default())
        .manage(PtyState::default())
        .manage(AudioState::default())
        .setup(|app| {
            // WebKitGTK (Linux desktop) auto-denies `getUserMedia` unless the
            // embedder answers the WebView's `permission-request` signal — wry
            // does not, so voice/dictation fails instantly with a permission
            // error and no prompt. Allow microphone (and camera) requests here so
            // the mic works; Linux has no per-app OS mic gate, so there is nothing
            // further to ask. Non-media requests are left to WebKit's default
            // (deny). No-op on macOS/Windows/mobile, where the webview or the mic
            // plugin already handles permission.
            #[cfg(target_os = "linux")]
            {
                use tauri::Manager;

                if let Some(window) = app.get_webview_window("main") {
                    let _ = window.with_webview(|platform_webview| {
                        use webkit2gtk::glib::prelude::*;
                        use webkit2gtk::{
                            PermissionRequestExt, UserMediaPermissionRequest, WebViewExt,
                        };

                        platform_webview
                            .inner()
                            .connect_permission_request(|_webview, request| {
                                if request
                                    .downcast_ref::<UserMediaPermissionRequest>()
                                    .is_some()
                                {
                                    request.allow();
                                    true
                                } else {
                                    false
                                }
                            });
                    });
                }
            }

            let _ = app;
            Ok(())
        })
        .invoke_handler(tauri::generate_handler![
            http_request,
            ws_open,
            ws_send,
            ws_close,
            pty_spawn,
            pty_write,
            pty_resize,
            pty_kill,
            audio_start_recording,
            audio_stop_recording,
            audio_cancel_recording,
            open_external,
            reveal_in_file_manager,
            set_window_translucency,
            marketplace_search,
            marketplace_fetch,
            oauth_login,
            oauth_status,
            oauth_logout,
            cookies_export,
            cookies_import,
            local_backend_spawn,
            local_backend_status,
            local_backend_stop,
            portal_login,
            portal_status,
            portal_discover_agents,
            portal_agent_sign_in,
            portal_logout
        ])
        .run(tauri::generate_context!())
        .expect("error while running Hermes Universal");
}
